import{_ as e,a as o,b as t}from"./chunks/koishi-onebot-setting.CwPzdrkF.js";import{_ as i,c as a,o as s,a2 as r}from"./chunks/framework.BX_emVE_.js";const v=JSON.parse('{"title":"Framework Integration","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/guide/integration.md","filePath":"en-US/guide/integration.md","lastUpdated":1717723122000}'),n={name:"en-US/guide/integration.md"},c=r('<h1 id="framework-integration" tabindex="-1">Framework Integration <a class="header-anchor" href="#framework-integration" aria-label="Permalink to &quot;Framework Integration&quot;">​</a></h1><h2 id="integrating-with-open-source-frameworks" tabindex="-1">Integrating with Open Source Frameworks <a class="header-anchor" href="#integrating-with-open-source-frameworks" aria-label="Permalink to &quot;Integrating with Open Source Frameworks&quot;">​</a></h2><p>Using Koishi and NoneBot as examples.</p><details class="details custom-block"><summary>Configuring Koishi</summary><ol><li><p>Search for <code>onebot</code> in the Koishi plugin market and install <code>adapter-onebot</code> as shown below:</p><p><img src="'+e+'" alt="koishi-install-onebot"></p></li><li><p>After installation, click on modify → configuration</p><p><img src="'+o+'" alt="koishi-onebot-go-setting"></p></li><li><p>Configure OneBot</p><p>Here&#39;s an example using WS reverse connection:</p><ul><li><code>selfId</code> is your bot&#39;s QQ number</li><li><code>token</code> should match the token configured in NapCat. If no token is configured, leave it blank.</li><li>Select protocol as ws-reverse</li></ul><p>Leave other configurations as default, click save, and then enable the plugin.</p><p><img src="'+t+'" alt="koishi-onebot-setting"></p><p>After configuration, add the WS reverse address in NapCat&#39;s settings. The WS reverse address for Koishi OneBot is <code>ws://127.0.0.1:5140/onebot</code>. Once added, click save.</p></li></ol></details><details class="details custom-block"><summary>Configuring NoneBot</summary><ol><li><p>Configure NoneBot</p><p>Assuming you have installed the OneBot adapter.</p><p>By default, NoneBot enables reverse ws. If you encounter a 403 error, it may be due to default configuration issues and requires configuring a <code>token</code> for a normal connection. The specific method is to modify the NoneBot configuration file <code>.env</code> and add <code>ONEBOT_ACCESS_TOKEN=your_token_configured_in_NapCat</code>.</p><p>Then, start NoneBot and you will see the port number output by NoneBot, such as <code>8080</code>.</p></li><li><p>Configure NapCat</p><p>Add the reverse ws address in NapCat settings, the address is <code>ws://127.0.0.1:8080/onebot/v11/ws</code>, where <code>8080</code> is the port number output by NoneBot, and <code>/onebot/v11/ws</code> is the default path for NoneBot onebot adapter.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Always remember: the <code>token</code> configured in NapCat must match the one configured in NoneBot!</p></div></li></ol></details><h2 id="configuring-http-service" tabindex="-1">Configuring HTTP Service <a class="header-anchor" href="#configuring-http-service" aria-label="Permalink to &quot;Configuring HTTP Service&quot;">​</a></h2><p>Configuring the HTTP service involves two main aspects: one is the HTTP listening port (to be called by your application), and the other is the HTTP reporting address (to be called by NapCat).</p><details class="details custom-block"><summary>HTTP Listening Port</summary><p>For example, if the configured port number is <code>3000</code>, the API address would be <code>http://localhost:3000</code>.</p></details><details class="details custom-block"><summary>HTTP Reporting Address</summary><p>When NapCat receives messages or other events, it reports them to this address via a <code>POST</code> request.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The reporting address must start with <code>http://</code></p></div></details><h2 id="configuring-websocket-service" tabindex="-1">Configuring WebSocket Service <a class="header-anchor" href="#configuring-websocket-service" aria-label="Permalink to &quot;Configuring WebSocket Service&quot;">​</a></h2><p>In the OneBot 11 standard, the definitions of &quot;forward WS&quot; and &quot;reverse WS&quot; are somewhat ambiguous. Here&#39;s a clear distinction: forward refers to <strong>accepting</strong> WS connections from the application side, while reverse refers to NapCat actively connecting to the reverse WS address listened by the application side.</p><details class="details custom-block"><summary>Forward WS Configuration</summary><p>For example, if the configured port number is <code>3001</code>, then the WS address configured on the application side should be <code>ws://localhost:3001</code>.</p></details><details class="details custom-block"><summary>Reverse WS Configuration</summary><p>For example, if NoneBot2 is configured with a OneBot port of <code>8080</code> and a path of <code>/onebot/v11/ws</code>, then the configured reverse WS address is <code>ws://localhost:8080/onebot/v11/ws</code>.</p></details>',13),d=[c];function l(p,u,h,m,g,f){return s(),a("div",null,d)}const w=i(n,[["render",l]]);export{v as __pageData,w as default};
